+void tsfile_device_id_free_contents(DeviceID* d) {
+    if (d == nullptr) {
+        return;
+    }
+    free(d->path);
+    d->path = nullptr;
+    free(d->table_name);
+    d->table_name = nullptr;
+    if (d->segments != nullptr) {
+        for (uint32_t k = 0; k < d->segment_count; k++) {
+            free(d->segments[k]);
